3	export type Item = {
4	  type: string;
5	  material?: string;
6	  enchantment?: number;
7	  cursed?: boolean;
8	};
9	
10	export type QuoteInput = {
11	  items: Item[];
12	  customerYears: number;
13	  previousContracts: number;
14	};
15	
16	const PROCESSING_FEE = 5;
17	const COMPONENT_BLOCK_SIZE = 3;
18	const COMPONENT_BLOCK_PREMIUM = 60;
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const CURSE_SURCHARGE_RATE = 0.5;
21	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
22	const HIGH_ENCHANTMENT_THRESHOLD = 5;
23	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
24	const LOYALTY_DISCOUNT_RATE = 0.2;
25	const LOYALTY_YEARS_THRESHOLD = 2;
26	const FOLLOWUP_DISCOUNT_RATE = 0.15;
27	
28	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
29	  sword: 100,
30	  amulet: 60,
31	  staff: 80,
32	  potion: 40,
33	  rune: 25,
34	  moonstone: 25,
35	};
36	
37	function groupByType(items: Item[]): Map<string, Item[]> {
38	  const groups = new Map<string, Item[]>();
39	  for (const item of items) {
40	    const group = groups.get(item.type) ?? [];
41	    group.push(item);
42	    groups.set(item.type, group);
43	  }
44	  return groups;
45	}
46	
47	function premiumForGroup(type: string, group: Item[]): number {
48	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
49	    return COMPONENT_BLOCK_PREMIUM;
50	  }
51	  return group.length * BASE_PREMIUM_BY_TYPE[type];
52	}
53	
54	function itemPremium(item: Item): number {
55	  const base = BASE_PREMIUM_BY_TYPE[item.type];
56	  let premium = base;
57	  if (item.cursed) {
58	    premium += base * CURSE_SURCHARGE_RATE;
59	  }
60	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
61	    premium += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
62	  }
63	  return premium;
64	}
65	
66	function hasCursedItem(items: Item[]): boolean {
67	  return items.some((item) => item.cursed);
68	}
69	
70	function hasHighEnchantmentItem(items: Item[]): boolean {
71	  return items.some(
72	    (item) => item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD,
73	  );
74	}
75	
76	function hasItemModifier(items: Item[]): boolean {
77	  return hasCursedItem(items) || hasHighEnchantmentItem(items);
78	}
79	
80	function baseTotalForItems(items: Item[]): number {
81	  return items.reduce((sum, item) => sum + BASE_PREMIUM_BY_TYPE[item.type], 0);
82	}
83	
84	function premiumForItems(items: Item[]): number {
85	  if (hasItemModifier(items)) {
86	    return items.reduce((sum, item) => sum + itemPremium(item), 0);
87	  }
88	  let total = 0;
89	  for (const [type, group] of groupByType(items)) {
90	    total += premiumForGroup(type, group);
91	  }
92	  return total;
93	}
94	
95	function isFirstContract(input: QuoteInput): boolean {
96	  return input.customerYears === 0 && input.previousContracts === 0;
97	}
98	
99	function qualifiesForLoyaltyDiscount(input: QuoteInput): boolean {
100	  return input.customerYears >= LOYALTY_YEARS_THRESHOLD;
101	}
102	
103	function qualifiesForFollowupDiscount(input: QuoteInput): boolean {
104	  return input.previousContracts >= 1;
105	}
106	
107	export function quote(input: QuoteInput): number {
108	  let premium = premiumForItems(input.items);
109	  if (hasItemModifier(input.items) && isFirstContract(input)) {
110	    premium += baseTotalForItems(input.items) * FIRST_INSURANCE_SURCHARGE_RATE;
111	  }
112	  if (qualifiesForLoyaltyDiscount(input)) {
113	    premium *= 1 - LOYALTY_DISCOUNT_RATE;
114	  }
115	  if (qualifiesForFollowupDiscount(input)) {
116	    premium *= 1 - FOLLOWUP_DISCOUNT_RATE;
117	  }
118	  return premium + PROCESSING_FEE;
119	}
